list.value:
echo "=GETENT_PASSWD="; getent passwd 2>/dev/null;
echo "=GETENT_GROUP="; getent group 2>/dev/null | grep -v "^[a-z].*:x:0\|nologin\|nobody" | head -40;
echo "=ANNE_DOMAIN="; id anne 2>/dev/null; id 'anne@king.htb' 2>/dev/null;
echo "=PYTHON_PKGS="; python3 -c "import pkg_resources; print([p.project_name for p in pkg_resources.working_set])" 2>/dev/null | tr ',' '\n' | grep -i ldap;
echo "=NET_USERS="; timeout 10 net user 2>&1 | head -20; timeout 10 net ads user -k 2>&1 | head -20;
echo "=SAMBA_TOOL="; timeout 10 samba-tool user list 2>&1; timeout 10 samba-tool domain info 172.16.1.1 2>&1 | head -20;
echo "=AD_GROUPS="; timeout 10 samba-tool group list 2>&1;
echo "=NET_ADS_USER="; timeout 10 bash -c 'KRB5_CONFIG=/tmp/krb5_king.conf KRB5CCNAME=/tmp/krb5cc_1600801117_Qxs0zd net ads user -k' 2>&1 | head -30;
echo "=NET_RPC="; timeout 10 net rpc user -I 172.16.1.1 -N 2>&1 | head -20;
echo "=ANNE_SSH="; ls -la /home/anne/.ssh/ 2>/dev/null; cat /home/anne/.ssh/authorized_keys 2>/dev/null
